const uploadSection = document.getElementById('uploadSection');
const uploadArea = document.getElementById('uploadArea');
const fileInput = document.getElementById('fileInput');
const editorSection = document.getElementById('editorSection');
const previewCanvas = document.getElementById('previewCanvas');
const dateInput = document.getElementById('dateInput');
const timeInput = document.getElementById('timeInput');
const locationInput = document.getElementById('locationInput');
const sizeSlider = document.getElementById('sizeSlider');
const sizeValue = document.getElementById('sizeValue');
const downloadBtn = document.getElementById('downloadBtn');
const reuploadBtn = document.getElementById('reuploadBtn');
const toggleLogoBtn = document.getElementById('toggleLogoBtn');

const TARGET_WIDTH = 1279;
const TARGET_HEIGHT = 1706;
const ASPECT_RATIO = TARGET_WIDTH / TARGET_HEIGHT;

let currentImage = null;
let watermarkColor = 'white';
let watermarkScale = 1.0;
let showLogo = true;
let zoom = 1.0;
let panX = 0;
let panY = 0;
let isDragging = false;
let dragStartX = 0;
let dragStartY = 0;
let panStartX = 0;
let panStartY = 0;
let touchStartDist = 0;
let touchStartZoom = 1.0;
let touchStartPanX = 0;
let touchStartPanY = 0;
let touchCenterX = 0;
let touchCenterY = 0;

const MIN_ZOOM = 1.0;
const MAX_ZOOM = 5.0;
const ZOOM_STEP = 0.1;

const pinImg = new Image();
pinImg.src = 'data:image/png;base64,';
const logoImg = new Image();
logoImg.src = 'data:image/png;base64,';

const WEEKDAYS = ['星期日', '星期一', '星期二', '星期三', '星期四', '星期五', '星期六'];

function initDateTime() {
    const now = new Date();
    dateInput.value = now.toISOString().split('T')[0];
    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    timeInput.value = `${hh}:${mm}`;
}

function formatDate(dateVal) {
    if (!dateVal) return '';
    const d = new Date(dateVal + 'T00:00:00');
    const y = d.getFullYear();
    const m = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    const wd = WEEKDAYS[d.getDay()];
    return `${y}-${m}-${day} ${wd}`;
}

uploadArea.addEventListener('click', () => fileInput.click());

uploadArea.addEventListener('dragover', (e) => {
    e.preventDefault();
    uploadArea.classList.add('drag-over');
});

uploadArea.addEventListener('dragleave', () => {
    uploadArea.classList.remove('drag-over');
});

uploadArea.addEventListener('drop', (e) => {
    e.preventDefault();
    uploadArea.classList.remove('drag-over');
    const file = e.dataTransfer.files[0];
    if (file) handleFile(file);
});

fileInput.addEventListener('change', () => {
    const file = fileInput.files[0];
    if (file) handleFile(file);
});

function handleFile(file) {
    if (!file.type.startsWith('image/')) {
        alert('请上传图片文件（JPG / PNG / WEBP）');
        return;
    }
    const reader = new FileReader();
    reader.onload = (e) => {
        const img = new Image();
        img.onload = () => {
            currentImage = img;
            resetView();
            showEditor();
        };
        img.src = e.target.result;
    };
    reader.readAsDataURL(file);
}

function resetView() {
    zoom = 1.0;
    panX = 0;
    panY = 0;
}

function showEditor() {
    uploadSection.style.display = 'none';
    editorSection.style.display = 'block';
    if (!dateInput.value) initDateTime();
    renderPreview();
}

toggleLogoBtn.addEventListener('click', () => {
    showLogo = !showLogo;
    document.getElementById('toggleLogoText').textContent = showLogo ? '隐藏 Logo' : '显示 Logo';
    renderPreview();
});

reuploadBtn.addEventListener('click', () => {
    currentImage = null;
    editorSection.style.display = 'none';
    uploadSection.style.display = 'block';
    fileInput.value = '';
    resetView();
});

document.querySelectorAll('.color-btn').forEach(btn => {
    btn.addEventListener('click', () => {
        document.querySelectorAll('.color-btn').forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
        watermarkColor = btn.dataset.color;
        renderPreview();
    });
});

sizeSlider.addEventListener('input', () => {
    watermarkScale = parseInt(sizeSlider.value) / 100;
    sizeValue.textContent = sizeSlider.value + '%';
    renderPreview();
});

[dateInput, timeInput, locationInput].forEach(input => {
    input.addEventListener('input', renderPreview);
});

function getCropRect(img) {
    const imgW = img.naturalWidth;
    const imgH = img.naturalHeight;
    const imgRatio = imgW / imgH;

    let baseSW, baseSH;
    if (imgRatio > ASPECT_RATIO) {
        baseSH = imgH;
        baseSW = imgH * ASPECT_RATIO;
    } else {
        baseSW = imgW;
        baseSH = imgW / ASPECT_RATIO;
    }

    const cropW = baseSW / zoom;
    const cropH = baseSH / zoom;

    const centerX = imgW / 2;
    const centerY = imgH / 2;

    const sx = centerX - cropW / 2 + panX;
    const sy = centerY - cropH / 2 + panY;

    return { sx, sy, sw: cropW, sh: cropH };
}

function clampPan() {
    if (!currentImage) return;
    const imgW = currentImage.naturalWidth;
    const imgH = currentImage.naturalHeight;
    const crop = getCropRect(currentImage);
    const maxPanX = (imgW - crop.sw) / 2;
    const maxPanY = (imgH - crop.sh) / 2;
    panX = Math.max(-maxPanX, Math.min(panX, maxPanX));
    panY = Math.max(-maxPanY, Math.min(panY, maxPanY));
}

function renderPreview() {
    if (!currentImage) return;

    const canvas = previewCanvas;
    const displayMaxWidth = 400;
    const scale = displayMaxWidth / TARGET_WIDTH;
    const displayW = displayMaxWidth;
    const displayH = Math.round(TARGET_HEIGHT * scale);

    canvas.width = displayW;
    canvas.height = displayH;

    const ctx = canvas.getContext('2d');
    const crop = getCropRect(currentImage);
    ctx.drawImage(currentImage, crop.sx, crop.sy, crop.sw, crop.sh, 0, 0, displayW, displayH);

    drawWatermark(ctx, displayW, displayH);
}

previewCanvas.addEventListener('wheel', (e) => {
    e.preventDefault();
    if (!currentImage) return;

    const rect = previewCanvas.getBoundingClientRect();
    const mouseX = (e.clientX - rect.left) / rect.width;
    const mouseY = (e.clientY - rect.top) / rect.height;

    const oldZoom = zoom;
    const delta = e.deltaY > 0 ? -ZOOM_STEP : ZOOM_STEP;
    zoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, zoom + delta));

    if (zoom !== oldZoom) {
        const crop = getCropRect(currentImage);
        const imgW = currentImage.naturalWidth;
        const imgH = currentImage.naturalHeight;
        const oldCropW = crop.sw * zoom / oldZoom;
        const oldCropH = crop.sh * zoom / oldZoom;
        const newCropW = crop.sw;
        const newCropH = crop.sh;

        const worldX = (mouseX - 0.5) * oldCropW + (panX + imgW / 2);
        const worldY = (mouseY - 0.5) * oldCropH + (panY + imgH / 2);

        panX = worldX - imgW / 2 - (mouseX - 0.5) * newCropW;
        panY = worldY - imgH / 2 - (mouseY - 0.5) * newCropH;
        clampPan();
        renderPreview();
    }
}, { passive: false });

previewCanvas.addEventListener('mousedown', (e) => {
    if (!currentImage) return;
    isDragging = true;
    dragStartX = e.clientX;
    dragStartY = e.clientY;
    panStartX = panX;
    panStartY = panY;
    previewCanvas.style.cursor = 'grabbing';
});

window.addEventListener('mousemove', (e) => {
    if (!isDragging || !currentImage) return;
    const crop = getCropRect(currentImage);
    const rect = previewCanvas.getBoundingClientRect();
    const scaleX = crop.sw / rect.width;
    const scaleY = crop.sh / rect.height;
    const dx = (e.clientX - dragStartX) * scaleX;
    const dy = (e.clientY - dragStartY) * scaleY;
    panX = panStartX - dx;
    panY = panStartY - dy;
    clampPan();
    renderPreview();
});

window.addEventListener('mouseup', () => {
    if (isDragging) {
        isDragging = false;
        previewCanvas.style.cursor = '';
    }
});

window.addEventListener('mouseleave', () => {
    if (isDragging) {
        isDragging = false;
        previewCanvas.style.cursor = '';
    }
});

previewCanvas.addEventListener('touchstart', (e) => {
    if (!currentImage) return;
    e.preventDefault();
    const touches = e.touches;
    if (touches.length === 1) {
        isDragging = true;
        dragStartX = touches[0].clientX;
        dragStartY = touches[0].clientY;
        panStartX = panX;
        panStartY = panY;
    } else if (touches.length === 2) {
        isDragging = false;
        const dx = touches[1].clientX - touches[0].clientX;
        const dy = touches[1].clientY - touches[0].clientY;
        touchStartDist = Math.sqrt(dx * dx + dy * dy);
        touchStartZoom = zoom;
        touchStartPanX = panX;
        touchStartPanY = panY;
        touchCenterX = (touches[0].clientX + touches[1].clientX) / 2;
        touchCenterY = (touches[0].clientY + touches[1].clientY) / 2;
    }
}, { passive: false });

previewCanvas.addEventListener('touchmove', (e) => {
    if (!currentImage) return;
    e.preventDefault();
    const touches = e.touches;
    if (touches.length === 1 && isDragging) {
        const crop = getCropRect(currentImage);
        const rect = previewCanvas.getBoundingClientRect();
        const scaleX = crop.sw / rect.width;
        const scaleY = crop.sh / rect.height;
        const dx = (touches[0].clientX - dragStartX) * scaleX;
        const dy = (touches[0].clientY - dragStartY) * scaleY;
        panX = panStartX - dx;
        panY = panStartY - dy;
        clampPan();
        renderPreview();
    } else if (touches.length === 2) {
        const dx = touches[1].clientX - touches[0].clientX;
        const dy = touches[1].clientY - touches[0].clientY;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (touchStartDist > 0) {
            const oldZoom = zoom;
            zoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, touchStartZoom * (dist / touchStartDist)));
            const crop = getCropRect(currentImage);
            const imgW = currentImage.naturalWidth;
            const imgH = currentImage.naturalHeight;
            const oldCropW = crop.sw * zoom / oldZoom;
            const oldCropH = crop.sh * zoom / oldZoom;
            const newCropW = crop.sw;
            const newCropH = crop.sh;
            const rect = previewCanvas.getBoundingClientRect();
            const mx = (touchCenterX - rect.left) / rect.width;
            const my = (touchCenterY - rect.top) / rect.height;
            panX = touchStartPanX + (mx - 0.5) * (oldCropW - newCropW);
            panY = touchStartPanY + (my - 0.5) * (oldCropH - newCropH);
            clampPan();
            renderPreview();
        }
    }
}, { passive: false });

previewCanvas.addEventListener('touchend', (e) => {
    if (!currentImage) return;
    if (e.touches.length === 0) {
        isDragging = false;
        touchStartDist = 0;
    }
});

function wrapText(ctx, text, maxWidth) {
    const chars = text.split('');
    const lines = [];
    let currentLine = '';
    for (const ch of chars) {
        const testLine = currentLine + ch;
        if (ctx.measureText(testLine).width > maxWidth && currentLine.length > 0) {
            lines.push(currentLine);
            currentLine = ch;
        } else {
            currentLine = testLine;
        }
    }
    if (currentLine) lines.push(currentLine);
    return lines;
}

function drawWatermark(ctx, width, height) {
    const baseScale = width / TARGET_WIDTH;
    const s = baseScale * watermarkScale;

    const textColor = watermarkColor === 'white' ? 'rgba(255,255,255,0.9)' : 'rgba(0,0,0,0.8)';
    const shadowColor = 'rgba(0,0,0,0.65)';

    const dateStr = formatDate(dateInput.value);
    const timeStr = timeInput.value || '';
    const locationVal = locationInput.value.trim();

    if (!dateStr && !timeStr && !locationVal) return;

    const centerX = width / 2;
    const timeFontSize = Math.round(170 * s);
    const dateFontSize = Math.round(50 * s);
    const locationFontSize = Math.round(45 * s);
    const lineSpacing = Math.round(8 * s);
    const maxLineWidth = width - 120 * s;

    const pinHeight = Math.round(52 * s);
    const pinWidth = Math.round(pinHeight * 97 / 268 * 1.5);

    const logoHeight = Math.round(60 * baseScale);
    const logoWidth = Math.round(logoHeight * 1662 / 380);

    ctx.save();

    ctx.shadowColor = shadowColor;
    ctx.shadowBlur = 8 * s;
    ctx.shadowOffsetX = 0;
    ctx.shadowOffsetY = 4 * s;

    const allLines = [];

    if (timeStr) {
        allLines.push({ type: 'timeLine', text: timeStr });
    }

    const topRowParts = [];
    if (dateStr) {
        topRowParts.push({ type: 'text', value: dateStr, fontSize: dateFontSize });
    }
    if (locationVal) {
        if (topRowParts.length > 0) {
            topRowParts.push({ type: 'gap', value: 30 * s });
        }
        topRowParts.push({ type: 'pin' });
        topRowParts.push({ type: 'gap', value: 6 * s });
        topRowParts.push({ type: 'text', value: locationVal, fontSize: locationFontSize, wrap: true });
    }

    if (topRowParts.length > 0) {
        let nonWrapWidth = 0;
        for (const part of topRowParts) {
            if (part.type === 'text' && !part.wrap) {
                ctx.font = `${part.fontSize}px "PingFang SC", "Microsoft YaHei", "Helvetica Neue", sans-serif`;
                nonWrapWidth += ctx.measureText(part.value).width;
            } else if (part.type === 'pin') {
                nonWrapWidth += pinWidth + 6 * s;
            } else if (part.type === 'gap') {
                nonWrapWidth += part.value;
            }
        }

        const wrapPart = topRowParts.find(p => p.type === 'text' && p.wrap);
        if (wrapPart) {
            ctx.font = `${wrapPart.fontSize}px "PingFang SC", "Microsoft YaHei", "Helvetica Neue", sans-serif`;
            const wrapMaxWidth = maxLineWidth - nonWrapWidth;
            const wrappedLines = wrapText(ctx, wrapPart.value, Math.max(wrapMaxWidth, 50 * s));

            if (wrappedLines.length === 1) {
                allLines.push({ type: 'topRow', parts: topRowParts, wrapText: wrappedLines[0] });
            } else {
                const firstLineParts = topRowParts.filter(p => p !== wrapPart);
                allLines.push({ type: 'topRow', parts: firstLineParts, wrapText: null });
                for (const wl of wrappedLines) {
                    allLines.push({ type: 'locationLine', text: wl });
                }
            }
        } else {
            allLines.push({ type: 'topRow', parts: topRowParts, wrapText: null });
        }
    }

    let totalHeight = 0;
    for (let i = 0; i < allLines.length; i++) {
        const line = allLines[i];
        if (line.type === 'timeLine') {
            totalHeight += timeFontSize;
        } else if (line.type === 'topRow') {
            totalHeight += dateFontSize;
        } else {
            totalHeight += locationFontSize;
        }
        if (i < allLines.length - 1) totalHeight += lineSpacing;
    }

    const bottomMargin = 120 * s;
    let currentY = height - bottomMargin - totalHeight;

    ctx.textBaseline = 'top';

    for (const line of allLines) {
        if (line.type === 'timeLine') {
            ctx.font = `${timeFontSize}px "PingFang SC", "Microsoft YaHei", "Helvetica Neue", sans-serif`;
            ctx.fillStyle = textColor;
            ctx.textAlign = 'center';
            ctx.fillText(line.text, centerX, currentY);
            currentY += timeFontSize + lineSpacing;

        } else if (line.type === 'topRow') {
            let rowWidth = 0;
            for (const part of line.parts) {
                if (part.type === 'text' && !part.wrap) {
                    ctx.font = `${part.fontSize}px "PingFang SC", "Microsoft YaHei", "Helvetica Neue", sans-serif`;
                    rowWidth += ctx.measureText(part.value).width;
                } else if (part.type === 'pin') {
                    rowWidth += pinWidth + 6 * s;
                } else if (part.type === 'gap') {
                    rowWidth += part.value;
                }
            }
            if (line.wrapText) {
                ctx.font = `${locationFontSize}px "PingFang SC", "Microsoft YaHei", "Helvetica Neue", sans-serif`;
                rowWidth += ctx.measureText(line.wrapText).width;
            }

            let drawX = centerX - rowWidth / 2;
            const rowHeight = dateFontSize;

            for (const part of line.parts) {
                if (part.type === 'text' && !part.wrap) {
                    ctx.font = `${part.fontSize}px "PingFang SC", "Microsoft YaHei", "Helvetica Neue", sans-serif`;
                    ctx.fillStyle = textColor;
                    ctx.textAlign = 'left';
                    const textOffsetY = (rowHeight - part.fontSize) / 2;
                    ctx.fillText(part.value, drawX, currentY + textOffsetY);
                    drawX += ctx.measureText(part.value).width;
                } else if (part.type === 'pin') {
                    const pinOffsetY = (rowHeight + locationFontSize) / 2 - pinHeight - 9 * s;
                    if (pinImg.complete) ctx.drawImage(pinImg, drawX, currentY + pinOffsetY, pinWidth, pinHeight);
                    drawX += pinWidth + 6 * s;
                } else if (part.type === 'gap') {
                    drawX += part.value;
                }
            }
            if (line.wrapText) {
                ctx.font = `${locationFontSize}px "PingFang SC", "Microsoft YaHei", "Helvetica Neue", sans-serif`;
                ctx.fillStyle = textColor;
                ctx.textAlign = 'left';
                const textOffsetY = (rowHeight - locationFontSize) / 2;
                ctx.fillText(line.wrapText, drawX, currentY + textOffsetY);
            }
            currentY += rowHeight + lineSpacing;

        } else if (line.type === 'locationLine') {
            ctx.font = `${locationFontSize}px "PingFang SC", "Microsoft YaHei", "Helvetica Neue", sans-serif`;
            ctx.fillStyle = textColor;
            ctx.textAlign = 'center';
            ctx.fillText(line.text, centerX, currentY);
            currentY += locationFontSize + lineSpacing;
        }
    }

    if (showLogo) {
        const logoMarginX = 50 * baseScale;
        const logoMarginBottom = 20 * baseScale;
        const logoX = width - logoWidth - logoMarginX;
        const logoY = height - logoHeight - logoMarginBottom;
        ctx.imageSmoothingEnabled = true;
        ctx.imageSmoothingQuality = 'high';
        if (logoImg.complete) ctx.drawImage(logoImg, logoX, logoY, logoWidth, logoHeight);
    }

    ctx.restore();
}

downloadBtn.addEventListener('click', () => {
    if (!currentImage) return;

    const canvas = document.createElement('canvas');
    canvas.width = TARGET_WIDTH;
    canvas.height = TARGET_HEIGHT;
    const ctx = canvas.getContext('2d');

    const crop = getCropRect(currentImage);
    ctx.drawImage(currentImage, crop.sx, crop.sy, crop.sw, crop.sh, 0, 0, TARGET_WIDTH, TARGET_HEIGHT);

    drawWatermark(ctx, TARGET_WIDTH, TARGET_HEIGHT);

    const dateVal = dateInput.value || 'nodate';
    const timeVal = (timeInput.value || 'notime').replace(/:/g, '-');
    const filename = `${dateVal}_${timeVal}.jpg`;

    if (canvas.toBlob) {
        canvas.toBlob((blob) => {
            if (blob) {
                const url = URL.createObjectURL(blob);
                triggerDownload(url, filename);
                URL.revokeObjectURL(url);
            } else {
                const dataUrl = canvas.toDataURL('image/jpeg', 0.95);
                triggerDownload(dataUrl, filename);
            }
        }, 'image/jpeg', 0.95);
    } else {
        const dataUrl = canvas.toDataURL('image/jpeg', 0.95);
        triggerDownload(dataUrl, filename);
    }
});

function triggerDownload(url, filename) {
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
}

const themeToggle = document.getElementById('themeToggle');
let isDark = localStorage.getItem('theme') !== 'light';

function updateTheme() {
    document.body.setAttribute('data-theme', isDark ? 'dark' : 'light');
    themeToggle.textContent = isDark ? '☀️' : '🌙';
    localStorage.setItem('theme', isDark ? 'dark' : 'light');
}

themeToggle.addEventListener('click', () => {
    isDark = !isDark;
    updateTheme();
});

updateTheme();

initDateTime();
